import React, { useState, useEffect, useCallback } from 'react';
import './CreateCombinedMaterial.css'; // Import CSS for styling

const CombinedMaterialInputForm = ({
    onClose,
    fetchAPI,
    apiBaseUrl,
}) => {
    // Initialize state
    const initialComboMat = {
        name: '',
        description: '',
        submaterials: [],
    };

    const [comboMat, setComboMat] = useState(initialComboMat);
    const [error, setError] = useState(null);
    const [materials, setMaterials] = useState([]);
    const [materialChanges, setMaterialChanges] = useState([]);


    const fetchData = useCallback(async () => {
        try {
            const MaterialData = await fetchAPI(`${apiBaseUrl}/materiallist`);
            const materialChangesData = await fetchAPI(`${apiBaseUrl}/materialchangesAPI`);
            setMaterials(MaterialData);
            setMaterialChanges(materialChangesData);

        } catch (error) {
            setError(error.message);
        }
    }, [fetchAPI, apiBaseUrl]);

    useEffect(() => {
        fetchData();
    }, [fetchData]);

    // Define event handlers
    const handleChange = (e) => {
        const { name, value } = e.target;
        setComboMat((prevComboMat) => ({
            ...prevComboMat,
            [name]: value,
        }));
    };

    const handleSubmaterialChange = (index, field, value) => {
        const updatedSubmaterials = [...comboMat.submaterials];
        updatedSubmaterials[index][field] = value;
        setComboMat((prevComboMat) => ({
            ...prevComboMat,
            submaterials: updatedSubmaterials,
        }));
        const latestPriceEntry = materialChanges
      .filter(mp => mp.material_id === value)
      .sort((a, b) => b.change_id - a.change_id)[0];

    updatedSubmaterials[index].unitPrice = latestPriceEntry ? parseFloat(latestPriceEntry.price) : 0;
    };

    const saveCombinedMaterial = async () => {
        try {
            const payload = {
                name: comboMat.name,
                description: comboMat.description,
                submaterials: comboMat.submaterials,
            };
            await fetchAPI(`${apiBaseUrl}/saveCombinedMaterial`, {
                method: 'POST',
                headers: {
                    'Content-Type': 'application/json',
                },
                body: JSON.stringify(payload),
            });
            alert('Combined material saved successfully!');
            setComboMat(initialComboMat);
            onClose();
        } catch (error) {
            alert(`Error: ${error.message}`);
        }
    };

    const addMaterial = () => {
        setComboMat((prevComboMat) => ({
            ...prevComboMat,
            submaterials: [
                ...prevComboMat.submaterials,
                { materialId: '', multiplier: 0, unitPrice: 0 }, // Set initial values here
            ],
        }));
    };
    

    const removeMaterial = (index) => {
        const updatedMaterials = comboMat.submaterials.filter((_, i) => i !== index);
        setComboMat((prevComboMat) => ({
            ...prevComboMat,
            submaterials: updatedMaterials,
        }));
    };
    

    if (error) return <div>Error: {error}</div>;

    return (
        <div className="material-input-form">
            <h3>Combine Materials</h3>
            <span className="close-popup" onClick={onClose}>
                &times;
            </span>
            <div className="form-row">
                <div className="form-group">
                    <label htmlFor="comboName">Combo Name</label>
                    <input
                        id="comboName"
                        type="text"
                        name="name"
                        value={comboMat.name}
                        onChange={handleChange}
                        placeholder="Enter combined material name"
                        className="form-control"
                    />
                </div>
                <div className="form-group">
                    <label htmlFor="description">Description</label>
                    <textarea
                        id="description"
                        name="description"
                        value={comboMat.description}
                        onChange={handleChange}
                        placeholder="Enter Description"
                        className="form-control"
                    />
                </div>
            </div>

            {materials.length > 0 &&
                comboMat.submaterials.map((selection, index) => (
                    <div key={index} className="material-selection">
                        <div className="form-row">
                            <div className="form-group">
                                <label>Material</label>
                                <select
                                    value={selection.materialId}
                                    onChange={(e) => handleSubmaterialChange(index, 'materialId', e.target.value)}
                                    className="form-control"
                                >
                                    <option value="">Select Material</option>
                                    {materials.map(material => (
                                        <option key={material.matid} value={material.matid}>{material.name}</option>
                                    ))}
                                </select>
                            </div>
                            <div className="form-group">
                                <label>Multiplier</label>
                                <input
                                    type="number"
                                    value={selection.multiplier}
                                    onChange={(e) => handleSubmaterialChange(index, 'multiplier', e.target.value)}
                                    className="form-control"
                                />
                            </div>
                            <div className="price-remove-container">
                                <div className="unit-price">
                                    <span>Unit Price: {parseFloat(selection.price).toFixed(2)}</span>
                                </div>
                            </div>
                            <div className="price-remove-container">
                                {comboMat.submaterials.length > 1 && (
                                    <button className="remove-btn" onClick={() => removeMaterial(index)}>Remove</button>
                                )}
                            </div>
                        </div>
                    </div>
                ))}
            <button className="btn btn-primary add-btn" onClick={addMaterial}>
                Add Material
            </button>
            <button className="btn btn-success save-btn" onClick={saveCombinedMaterial}>
                Save Combined Material
            </button>
        </div>
    );
};

export default CombinedMaterialInputForm;
